import type { ColorFieldCompactEmits, ColorFieldCompactProps, ColorFieldUi } from '@soybeanjs/headless/color-field';
import type { ClassValue } from '@soybeanjs/headless/types';
import type { ThemeSize } from '@/theme';

/**
 * Properties for the ColorField component.
 */
export interface ColorFieldProps extends ColorFieldCompactProps {
  /**
   * Additional class names applied to the root element.
   */
  class?: ClassValue;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<ColorFieldUi>;
}

/**
 * Events for the ColorField component.
 */
export type ColorFieldEmits = ColorFieldCompactEmits;

export { default as SColorField } from './color-field.vue';

export type * from '@soybeanjs/headless/color-field';
export type * from './types';

// @unocss-include
import { scv } from '@soybeanjs/cva';

export const colorFieldVariants = scv({
  slots: {
    root: [
      'group flex items-center min-w-0 rounded-md border border-input bg-background transition-all-150',
      'outline-none focus-within:ring-3 focus-within:ring-offset-background focus-within:ring-primary/30',
      'data-[disabled]:opacity-60 data-[readonly]:bg-muted/40'
    ],
    input: [
      'flex-1 min-w-0 bg-transparent outline-none',
      'placeholder:text-muted-foreground',
      'disabled:cursor-not-allowed disabled:opacity-50'
    ]
  },
  variants: {
    size: {
      xs: {
        root: 'h-6 px-1.5 text-2xs gap-1'
      },
      sm: {
        root: 'h-7 px-2 text-xs gap-1.5'
      },
      md: {
        root: 'h-8 px-2.5 text-sm gap-2'
      },
      lg: {
        root: 'h-9 px-3 text-base gap-2.5'
      },
      xl: {
        root: 'h-10 px-3.5 text-lg gap-3'
      },
      '2xl': {
        root: 'h-12 px-4 text-xl gap-3.5'
      }
    }
  },
  defaultVariants: {
    size: 'md'
  }
});

import type { ThemeSize } from './types';

export const themeSizeMap: Record<ThemeSize, number> = {
  xs: 12,
  sm: 14,
  md: 16,
  lg: 18,
  xl: 20,
  '2xl': 24
};
export const miniSizeMap: Record<ThemeSize, ThemeSize> = {
  xs: 'xs',
  sm: 'xs',
  md: 'sm',
  lg: 'md',
  xl: 'lg',
  '2xl': 'xl'
};

export const themeSizeRatio = Object.fromEntries(
  Object.entries(themeSizeMap).map(([key, value]) => [key, value / themeSizeMap.md])
) as Record<ThemeSize, number>;
